# Concrete shape implementations using cross-module inheritance
from models import Shape, ShapeType, IArea, IPerimeter

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

    def __str__(self) -> str:
        return f"({self.x}, {self.y})"

class Rectangle(Shape, IArea, IPerimeter):
    width: float
    height: float
    top_left: Point

    def __init__(self, w: float, h: float, tl: Point, id: int):
        super().__init__(ShapeType.RECTANGLE, id)
        self.width = w
        self.height = h
        self.top_left = tl

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"Rectangle({self.width}, {self.height}) at {self.top_left}"

class Circle(Shape, IArea, IPerimeter):
    radius: float
    center: Point

    def __init__(self, r: float, c: Point, id: int):
        super().__init__(ShapeType.CIRCLE, id)
        self.radius = r
        self.center = c

    @override
    def area(self) -> float:
        pi: float = 3.14159
        return pi * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        pi: float = 3.14159
        return 2.0 * pi * self.radius

    @override
    def describe(self) -> str:
        return f"Circle(r={self.radius}) at {self.center}"

