# Geometry calculation utilities using interfaces from models module
from models import ShapeType

class GeometryCalculator:
    def total_area(self, shapes: list[IArea]) -> float:
        total: float = 0.0
        for shape in shapes:
            total += shape.area()
        return total

    def total_perimeter(self, shapes: list[IPerimeter]) -> float:
        total: float = 0.0
        for shape in shapes:
            total += shape.perimeter()
        return total

def describe_shape_type(st: ShapeType) -> str:
    if st == ShapeType.CIRCLE:
        return "circle"
    elif st == ShapeType.RECTANGLE:
        return "rectangle"
    else:
        return "unknown"
